func FastDesignerSearch(designers []entities.Designer, searchingID int) string {
	desMap := make(map[int]string)
	for _, des := range designers {
		desMap[des.ID] = des.Name
	}
	designerName, _ := desMap[searchingID]
	return designerName
}
